-- 02_schema.sql - Nestle diet-optimization demo schema
-- Generated by data/generate_sql.py. Run as the demo role RAI_DEMO_NESTLE_DIET.
USE DATABASE PK_NESTLE_DIET;
CREATE SCHEMA IF NOT EXISTS DIET COMMENT = 'Vegan diet/menu optimization demo: ingredients, recipes, nutrition, prices, persona targets.';
USE SCHEMA DIET;

-- commodity: One row per traded commodity input. Master/dimension; the cost and price-volatility backbone for ingredients.
CREATE OR REPLACE TABLE commodity (
    commodity_id VARCHAR NOT NULL COMMENT 'Commodity code (natural key), e.g. cocoa, coffee, wheat',
    commodity_name VARCHAR NOT NULL COMMENT 'Human-readable commodity name',
    unit VARCHAR NOT NULL COMMENT 'Quotation unit for the base price',
    base_price_usd_per_kg FLOAT NOT NULL COMMENT 'Reference price in USD per kg at index 1.00 (Jan 2025)',
    current_price_index FLOAT NOT NULL COMMENT 'Latest normalized price index (1.00 = Jan 2025)',
    current_price_usd_per_kg FLOAT NOT NULL COMMENT 'Latest price in USD per kg',
    peak_price_index FLOAT NOT NULL COMMENT 'Maximum price index observed over the history window',
    is_volatile BOOLEAN NOT NULL COMMENT 'TRUE for commodities with high recent price volatility (cocoa, coffee, olive oil)',
    CONSTRAINT pk_commodity PRIMARY KEY (commodity_id)
) COMMENT = 'One row per traded commodity input. Master/dimension; the cost and price-volatility backbone for ingredients.';
ALTER TABLE commodity SET CHANGE_TRACKING = TRUE;

-- commodity_price_history: One row per commodity per month. Time series of the monthly price index, Jan 2025 to Jun 2026, anchored to real commodity moves.
CREATE OR REPLACE TABLE commodity_price_history (
    commodity_id VARCHAR NOT NULL COMMENT 'Commodity code; FK to commodity',
    price_month DATE NOT NULL COMMENT 'First day of the month for this price observation',
    price_index FLOAT NOT NULL COMMENT 'Normalized price index (1.00 = Jan 2025)',
    price_usd_per_kg FLOAT NOT NULL COMMENT 'Price in USD per kg for the month',
    CONSTRAINT pk_commodity_price_history PRIMARY KEY (commodity_id, price_month),
    CONSTRAINT fk_commodity_price_history_commodity_id FOREIGN KEY (commodity_id) REFERENCES commodity (commodity_id)
) COMMENT = 'One row per commodity per month. Time series of the monthly price index, Jan 2025 to Jun 2026, anchored to real commodity moves.';
ALTER TABLE commodity_price_history SET CHANGE_TRACKING = TRUE;

-- ingredient: One row per ingredient or branded product. Master table carrying per-100g nutrition, cost, sustainability, and allergen/diet flags. Sourced from USDA FoodData Central (CC0), Open Food Facts (ODbL), and hand-authored fortified specialty items.
CREATE OR REPLACE TABLE ingredient (
    ingredient_id NUMBER NOT NULL COMMENT 'Surrogate key for the ingredient',
    ingredient_name VARCHAR NOT NULL COMMENT 'Display name of the ingredient or product',
    brand VARCHAR COMMENT 'Brand name for branded products; null for generic foods',
    is_branded BOOLEAN NOT NULL COMMENT 'TRUE if this is a branded retail product',
    source VARCHAR NOT NULL COMMENT 'Provenance: usda, off (Open Food Facts), or curated',
    source_id VARCHAR COMMENT 'Identifier in the source system (USDA fdc_id or OFF barcode)',
    food_group VARCHAR NOT NULL COMMENT 'Food group, e.g. grain, legume, plant_protein, nuts_seeds, vegetable, fruit',
    commodity_id VARCHAR NOT NULL COMMENT 'Primary commodity input; FK to commodity',
    is_fortified BOOLEAN NOT NULL COMMENT 'TRUE if the item is fortified (added vitamins/minerals)',
    is_estimated_micros BOOLEAN NOT NULL COMMENT 'TRUE if micronutrients were imputed from food-group medians (OFF products)',
    is_vegan BOOLEAN NOT NULL COMMENT 'TRUE if the ingredient is vegan',
    is_vegetarian BOOLEAN NOT NULL COMMENT 'TRUE if the ingredient is vegetarian',
    is_gluten_free BOOLEAN NOT NULL COMMENT 'TRUE if the ingredient is gluten free',
    nutriscore_grade VARCHAR COMMENT 'Nutri-Score grade a-e (Open Food Facts); null if unknown',
    nova_group NUMBER COMMENT 'NOVA processing group 1-4 (1 = unprocessed, 4 = ultra-processed)',
    cost_per_100g FLOAT NOT NULL COMMENT 'Estimated retail cost in USD per 100 g at current commodity prices',
    cost_per_100g_shock FLOAT NOT NULL COMMENT 'Estimated cost per 100 g under the commodity price-shock scenario',
    co2e_per_kg FLOAT NOT NULL COMMENT 'Greenhouse-gas footprint in kg CO2e per kg (Poore & Nemecek 2018 / OWID)',
    water_l_per_kg FLOAT NOT NULL COMMENT 'Freshwater withdrawal in liters per kg (Poore & Nemecek 2018 / OWID)',
    kcal FLOAT NOT NULL COMMENT 'Energy per 100 g (kcal)',
    protein_g FLOAT NOT NULL COMMENT 'Protein per 100 g (g)',
    carb_g FLOAT NOT NULL COMMENT 'Carbohydrate per 100 g (g)',
    fat_g FLOAT NOT NULL COMMENT 'Total fat per 100 g (g)',
    fiber_g FLOAT NOT NULL COMMENT 'Dietary fiber per 100 g (g)',
    sugars_g FLOAT NOT NULL COMMENT 'Total sugars per 100 g (g)',
    satfat_g FLOAT NOT NULL COMMENT 'Saturated fat per 100 g (g)',
    sodium_mg FLOAT NOT NULL COMMENT 'Sodium per 100 g (mg)',
    calcium_mg FLOAT NOT NULL COMMENT 'Calcium per 100 g (mg)',
    iron_mg FLOAT NOT NULL COMMENT 'Iron per 100 g (mg)',
    potassium_mg FLOAT NOT NULL COMMENT 'Potassium per 100 g (mg)',
    zinc_mg FLOAT NOT NULL COMMENT 'Zinc per 100 g (mg)',
    magnesium_mg FLOAT NOT NULL COMMENT 'Magnesium per 100 g (mg)',
    vitd_ug FLOAT NOT NULL COMMENT 'Vitamin D per 100 g (ug)',
    vitc_mg FLOAT NOT NULL COMMENT 'Vitamin C per 100 g (mg)',
    b12_ug FLOAT NOT NULL COMMENT 'Vitamin B12 per 100 g (ug)',
    has_gluten BOOLEAN NOT NULL COMMENT 'TRUE if the item contains gluten (wheat, barley, rye)',
    has_dairy BOOLEAN NOT NULL COMMENT 'TRUE if the item contains dairy',
    has_egg BOOLEAN NOT NULL COMMENT 'TRUE if the item contains egg',
    has_soy BOOLEAN NOT NULL COMMENT 'TRUE if the item contains soy',
    has_nuts BOOLEAN NOT NULL COMMENT 'TRUE if the item contains tree nuts',
    has_peanuts BOOLEAN NOT NULL COMMENT 'TRUE if the item contains peanuts',
    has_sesame BOOLEAN NOT NULL COMMENT 'TRUE if the item contains sesame',
    has_fish BOOLEAN NOT NULL COMMENT 'TRUE if the item contains fish or shellfish',
    CONSTRAINT pk_ingredient PRIMARY KEY (ingredient_id),
    CONSTRAINT fk_ingredient_commodity_id FOREIGN KEY (commodity_id) REFERENCES commodity (commodity_id)
) COMMENT = 'One row per ingredient or branded product. Master table carrying per-100g nutrition, cost, sustainability, and allergen/diet flags. Sourced from USDA FoodData Central (CC0), Open Food Facts (ODbL), and hand-authored fortified specialty items.';
ALTER TABLE ingredient SET CHANGE_TRACKING = TRUE;

-- recipe: One row per single-serving recipe. Each recipe is a bundle of ingredients (see recipe_ingredient) with nutrition, cost, and CO2e derived by summing the bill of materials.
CREATE OR REPLACE TABLE recipe (
    recipe_id NUMBER NOT NULL COMMENT 'Surrogate key for the recipe',
    recipe_name VARCHAR NOT NULL COMMENT 'Display name of the recipe',
    meal_type VARCHAR NOT NULL COMMENT 'Meal type the recipe serves: breakfast, main, or snack',
    cuisine VARCHAR NOT NULL COMMENT 'Cuisine style',
    servings NUMBER NOT NULL COMMENT 'Number of servings the recipe yields (1 = single serving)',
    prep_time_min NUMBER NOT NULL COMMENT 'Preparation time in minutes',
    n_ingredients NUMBER NOT NULL COMMENT 'Number of distinct ingredients in the recipe',
    total_grams FLOAT NOT NULL COMMENT 'Total edible mass of one serving in grams',
    is_vegan BOOLEAN NOT NULL COMMENT 'TRUE if all ingredients are vegan',
    is_vegetarian BOOLEAN NOT NULL COMMENT 'TRUE if all ingredients are vegetarian',
    is_gluten_free BOOLEAN NOT NULL COMMENT 'TRUE if all ingredients are gluten free',
    cost_usd FLOAT NOT NULL COMMENT 'Cost of one serving in USD at current commodity prices',
    cost_usd_shock FLOAT NOT NULL COMMENT 'Cost of one serving in USD under the commodity price-shock scenario',
    co2e_kg FLOAT NOT NULL COMMENT 'Greenhouse-gas footprint of one serving in kg CO2e',
    water_l FLOAT NOT NULL COMMENT 'Freshwater footprint of one serving in liters',
    kcal FLOAT NOT NULL COMMENT 'Energy per serving (kcal)',
    protein_g FLOAT NOT NULL COMMENT 'Protein per serving (g)',
    carb_g FLOAT NOT NULL COMMENT 'Carbohydrate per serving (g)',
    fat_g FLOAT NOT NULL COMMENT 'Total fat per serving (g)',
    fiber_g FLOAT NOT NULL COMMENT 'Dietary fiber per serving (g)',
    sugars_g FLOAT NOT NULL COMMENT 'Total sugars per serving (g)',
    satfat_g FLOAT NOT NULL COMMENT 'Saturated fat per serving (g)',
    sodium_mg FLOAT NOT NULL COMMENT 'Sodium per serving (mg)',
    calcium_mg FLOAT NOT NULL COMMENT 'Calcium per serving (mg)',
    iron_mg FLOAT NOT NULL COMMENT 'Iron per serving (mg)',
    potassium_mg FLOAT NOT NULL COMMENT 'Potassium per serving (mg)',
    zinc_mg FLOAT NOT NULL COMMENT 'Zinc per serving (mg)',
    magnesium_mg FLOAT NOT NULL COMMENT 'Magnesium per serving (mg)',
    vitd_ug FLOAT NOT NULL COMMENT 'Vitamin D per serving (ug)',
    vitc_mg FLOAT NOT NULL COMMENT 'Vitamin C per serving (mg)',
    b12_ug FLOAT NOT NULL COMMENT 'Vitamin B12 per serving (ug)',
    CONSTRAINT pk_recipe PRIMARY KEY (recipe_id)
) COMMENT = 'One row per single-serving recipe. Each recipe is a bundle of ingredients (see recipe_ingredient) with nutrition, cost, and CO2e derived by summing the bill of materials.';
ALTER TABLE recipe SET CHANGE_TRACKING = TRUE;

-- recipe_ingredient: One row per ingredient used in a recipe (the bill of materials). Junction between recipe and ingredient with the quantity used.
CREATE OR REPLACE TABLE recipe_ingredient (
    recipe_id NUMBER NOT NULL COMMENT 'Recipe; FK to recipe',
    ingredient_id NUMBER NOT NULL COMMENT 'Ingredient; FK to ingredient',
    ingredient_name VARCHAR NOT NULL COMMENT 'Denormalized ingredient name for readability',
    quantity_g FLOAT NOT NULL COMMENT 'Quantity of the ingredient in this recipe, in grams',
    CONSTRAINT pk_recipe_ingredient PRIMARY KEY (recipe_id, ingredient_id),
    CONSTRAINT fk_recipe_ingredient_recipe_id FOREIGN KEY (recipe_id) REFERENCES recipe (recipe_id),
    CONSTRAINT fk_recipe_ingredient_ingredient_id FOREIGN KEY (ingredient_id) REFERENCES ingredient (ingredient_id)
) COMMENT = 'One row per ingredient used in a recipe (the bill of materials). Junction between recipe and ingredient with the quantity used.';
ALTER TABLE recipe_ingredient SET CHANGE_TRACKING = TRUE;

-- persona: One row per demo persona. The optimization target profile.
CREATE OR REPLACE TABLE persona (
    persona_id VARCHAR NOT NULL COMMENT 'Persona code (natural key)',
    persona_name VARCHAR NOT NULL COMMENT 'Display name of the persona',
    description VARCHAR NOT NULL COMMENT 'Short description of the persona',
    sex VARCHAR NOT NULL COMMENT 'Biological sex used for nutrient reference values',
    age_years NUMBER NOT NULL COMMENT 'Age in years',
    weight_kg NUMBER NOT NULL COMMENT 'Body weight in kg (drives per-kg protein/carb targets)',
    activity_level VARCHAR NOT NULL COMMENT 'Activity level',
    sport VARCHAR NOT NULL COMMENT 'Primary sport / training modality',
    diet_pattern VARCHAR NOT NULL COMMENT 'Dietary pattern, e.g. vegan',
    target_energy_kcal NUMBER NOT NULL COMMENT 'Target daily energy intake in kcal',
    CONSTRAINT pk_persona PRIMARY KEY (persona_id)
) COMMENT = 'One row per demo persona. The optimization target profile.';
ALTER TABLE persona SET CHANGE_TRACKING = TRUE;

-- dietary_restriction: One row per dietary restriction. Reference for restriction rules that exclude ingredients carrying given allergen/diet flags.
CREATE OR REPLACE TABLE dietary_restriction (
    restriction_id VARCHAR NOT NULL COMMENT 'Restriction code (natural key)',
    restriction_name VARCHAR NOT NULL COMMENT 'Display name of the restriction',
    description VARCHAR NOT NULL COMMENT 'What the restriction excludes',
    excluded_flags VARCHAR NOT NULL COMMENT 'Pipe-delimited ingredient flags excluded by this restriction',
    CONSTRAINT pk_dietary_restriction PRIMARY KEY (restriction_id)
) COMMENT = 'One row per dietary restriction. Reference for restriction rules that exclude ingredients carrying given allergen/diet flags.';
ALTER TABLE dietary_restriction SET CHANGE_TRACKING = TRUE;

-- persona_restriction: One row per persona per active dietary restriction. Junction linking personas to the restrictions they follow.
CREATE OR REPLACE TABLE persona_restriction (
    persona_id VARCHAR NOT NULL COMMENT 'Persona; FK to persona',
    restriction_id VARCHAR NOT NULL COMMENT 'Restriction; FK to dietary_restriction',
    CONSTRAINT pk_persona_restriction PRIMARY KEY (persona_id, restriction_id),
    CONSTRAINT fk_persona_restriction_persona_id FOREIGN KEY (persona_id) REFERENCES persona (persona_id),
    CONSTRAINT fk_persona_restriction_restriction_id FOREIGN KEY (restriction_id) REFERENCES dietary_restriction (restriction_id)
) COMMENT = 'One row per persona per active dietary restriction. Junction linking personas to the restrictions they follow.';
ALTER TABLE persona_restriction SET CHANGE_TRACKING = TRUE;

-- persona_nutrient_target: One row per persona per nutrient. The optimization constraints (floor/ceiling/range) the daily menu must satisfy.
CREATE OR REPLACE TABLE persona_nutrient_target (
    persona_id VARCHAR NOT NULL COMMENT 'Persona; FK to persona',
    nutrient_code VARCHAR NOT NULL COMMENT 'Nutrient column code matching recipe/ingredient nutrition columns',
    nutrient_name VARCHAR NOT NULL COMMENT 'Human-readable nutrient name',
    unit VARCHAR NOT NULL COMMENT 'Unit of the min/max amounts',
    min_amount FLOAT NOT NULL COMMENT 'Minimum daily amount (floor); 0 if none',
    max_amount FLOAT COMMENT 'Maximum daily amount (ceiling); null if none',
    direction VARCHAR NOT NULL COMMENT 'Constraint type: floor, ceiling, or range',
    priority NUMBER NOT NULL COMMENT 'Constraint priority 1 (highest) to 3 (lowest)',
    CONSTRAINT pk_persona_nutrient_target PRIMARY KEY (persona_id, nutrient_code),
    CONSTRAINT fk_persona_nutrient_target_persona_id FOREIGN KEY (persona_id) REFERENCES persona (persona_id)
) COMMENT = 'One row per persona per nutrient. The optimization constraints (floor/ceiling/range) the daily menu must satisfy.';
ALTER TABLE persona_nutrient_target SET CHANGE_TRACKING = TRUE;

-- meal_slot: One row per meal slot in a daily plan. Defines how many recipes of which meal type fill each slot in the menu optimization.
CREATE OR REPLACE TABLE meal_slot (
    slot_id VARCHAR NOT NULL COMMENT 'Slot code (natural key): breakfast, lunch, dinner, snack',
    slot_name VARCHAR NOT NULL COMMENT 'Display name of the slot',
    eligible_meal_type VARCHAR NOT NULL COMMENT 'Recipe meal_type eligible for this slot',
    min_recipes NUMBER NOT NULL COMMENT 'Minimum recipes assigned to this slot',
    max_recipes NUMBER NOT NULL COMMENT 'Maximum recipes assigned to this slot',
    slot_order NUMBER NOT NULL COMMENT 'Display order of the slot within a day',
    CONSTRAINT pk_meal_slot PRIMARY KEY (slot_id)
) COMMENT = 'One row per meal slot in a daily plan. Defines how many recipes of which meal type fill each slot in the menu optimization.';
ALTER TABLE meal_slot SET CHANGE_TRACKING = TRUE;

-- status_quo_menu: One row per recipe in the persona's current 'favourite' daily menu. The fixed baseline whose cost spikes under a price shock; the Q3 re-solve protects against that spike.
CREATE OR REPLACE TABLE status_quo_menu (
    slot_id VARCHAR NOT NULL COMMENT 'Meal slot this recipe fills',
    recipe_id NUMBER NOT NULL COMMENT 'Recipe; FK to recipe',
    recipe_name VARCHAR NOT NULL COMMENT 'Denormalized recipe name for readability',
    cost_usd FLOAT NOT NULL COMMENT 'Cost of the recipe at current prices',
    cost_usd_shock FLOAT NOT NULL COMMENT 'Cost of the recipe under the price-shock scenario',
    CONSTRAINT pk_status_quo_menu PRIMARY KEY (slot_id, recipe_id),
    CONSTRAINT fk_status_quo_menu_recipe_id FOREIGN KEY (recipe_id) REFERENCES recipe (recipe_id)
) COMMENT = 'One row per recipe in the persona''s current ''favourite'' daily menu. The fixed baseline whose cost spikes under a price shock; the Q3 re-solve protects against that spike.';
ALTER TABLE status_quo_menu SET CHANGE_TRACKING = TRUE;
